import copy
class Solution:
    def reverseSubmatrix(self, grid, x, y, k):
        out = copy.deepcopy(grid)
        for r in range(k):
            src = grid[x + k - 1 - r]
            for c in range(k):
                out[x + r][y + c] = src[y + c]
        return out

