class Solution:
    def reverseSubmatrix(self, grid, x, y, k):
        for i in range(k // 2):
            top = x + i
            bot = x + k - 1 - i
            for c in range(y, y + k):
                grid[top][c], grid[bot][c] = grid[bot][c], grid[top][c]
        return grid

