var reverseSubmatrix = function(grid, x, y, k) {
    for (let i = 0; i < Math.floor(k / 2); i++) {
        const top = x + i, bot = x + k - 1 - i;
        for (let c = y; c < y + k; c++) {
            const t = grid[top][c];
            grid[top][c] = grid[bot][c];
            grid[bot][c] = t;
        }
    }
    return grid;
};
